#include <iostream>
#include <vector>
#include <random>
#include <algorithm>
#include <cmath>

// Define the chromosome (solution) type
using Chromosome = std::vector<int>; // Binary string

// Define the population type
using Population = std::vector<Chromosome>;

// Function to generate an initial population
Population generatePopulation(int populationSize, int chromosomeLength) {
    Population population;
    std::default_random_engine generator;
    std::bernoulli_distribution distribution(0.5); // 50% chance of 0 or 1

    for (int i = 0; i < populationSize; ++i) {
        Chromosome chromosome(chromosomeLength);
        for (int j = 0; j < chromosomeLength; ++j) {
            chromosome[j] = distribution(generator);
        }
        population.push_back(chromosome);
    }
    return population;
}

// Fitness function: sum of chromosome elements
int fitnessFunction(const Chromosome& chromosome) {
    int sum = 0;
    for (int bit : chromosome) {
        sum += bit;
    }
    return sum;
}

// Selection using tournament selection
Chromosome tournamentSelection(const Population& population, int tournamentSize) {
    int winner = -1;
    int maxFitness = -1;
    for (int i = 0; i < tournamentSize; ++i) {
        int randomIndex = rand() % population.size();
        int currentFitness = fitnessFunction(population[randomIndex]);
        if (currentFitness > maxFitness) {
            maxFitness = currentFitness;
            winner = randomIndex;
        }
    }
    return population[winner];
}

// Crossover function
Chromosome crossover(const Chromosome& parent1, const Chromosome& parent2) {
    int crossoverPoint = rand() % parent1.size();
    Chromosome child(parent1.size());
